public bool Apply(OtlpSpan span)
        {
            var fieldValue = OtlpSpan.GetFieldValue(span, Field);
            var isNot = Condition is FilterCondition.NotEqual or FilterCondition.NotContains;

            if (!isNot)
            {
                if (fieldValue.Value1 is not null && IsMatch(fieldValue.Value1))
                {
                    return true;
                }

                if (fieldValue.Value2 is not null && IsMatch(fieldValue.Value2))
                {
                    return true;
                }
            }
            else
            {
                if (fieldValue.Value1 is not null && IsMatch(fieldValue.Value1))
                {
                    if (fieldValue.Value2 is null || IsMatch(fieldValue.Value2))
                    {
                        return true;
                    }
                }
            }

            return false;
        }

private static RuntimeSpec GetVenvRuntimeSpec()
    {
        var python = FindPythonCommand();
        var hasVenv = IsCommandAvailable(python, "-m", "venv", "--help");

        var initializeArgs = hasVenv
            ? (string[])["-m", "venv", ".venv"]
            : ["-c", s_microvenvScript.Value, ".venv"];

        return new RuntimeSpec
        {
            Language = LanguageId,
            DisplayName = LanguageDisplayName,
            CodeGenLanguage = CodeGenTarget,
            DetectionPatterns = s_detectionPatterns,
            Initialize =
            [
                new CommandSpec
                {
                    Command = python,
                    Args = initializeArgs
                },
                new CommandSpec
                {
                    Command = s_venvPython,
                    Args = ["-m", "ensurepip", "--upgrade"]
                }
            ],
            InstallDependencies = new CommandSpec
            {
                Command = s_venvPython,
                Args = ["-m", "pip", "install", "-r", "apphost_requirements.txt"]
            },
            Execute = new CommandSpec
            {
                Command = s_venvPython,
                Args = ["{appHostFile}", "{args}"]
            }
        };
    }

private string MapParameterTypeToRust(AtsTypeRef? typeRef, bool isOptional)
    {
        if (typeRef is null)
        {
            return "Value";
        }

        // For primitives that are strings, use &str for parameters (more idiomatic)
        if (typeRef.Category == AtsTypeCategory.Primitive)
        {
            var baseType = typeRef.TypeId switch
            {
                AtsConstants.String or AtsConstants.Char => "&str",
                AtsConstants.Number => "f64",
                AtsConstants.Boolean => "bool",
                AtsConstants.Void => "()",
                AtsConstants.Any => "&Value",
                AtsConstants.DateTime or AtsConstants.DateTimeOffset or
                AtsConstants.DateOnly or AtsConstants.TimeOnly => "&str",
                AtsConstants.TimeSpan => "f64",
                AtsConstants.Guid or AtsConstants.Uri => "&str",
                AtsConstants.CancellationToken => "&CancellationToken",
                _ => "&Value"
            };
            return isOptional ? $"Option<{baseType}>" : baseType;
        }

        // For arrays/lists of strings, use Vec<String> since we need owned values
        // For other types, use the standard mapping
        return MapTypeRefToRust(typeRef, isOptional);
    }

private static string? EscapeArgList(Collection<string> args)
    {
        if (args.Count == 0)
        {
            return null;
        }

        StringBuilder? sb = null;

        foreach (var a in args)
        {
            if (string.IsNullOrWhiteSpace(a))
            {
                continue;
            }

            sb ??= new StringBuilder(args.Count * 2);
            if (sb.Length > 0)
            {
                sb.Append(' ');
            }

            var needsQuotes = a.Any(char.IsWhiteSpace) || a.Contains('"');
            if (needsQuotes)
            {
                sb.Append('"');
            }

            foreach (var c in a)
            {
                if (c == '"')
                {
                    sb.Append('\\'); // Escape quote
                }
                sb.Append(c);
            }

            if (needsQuotes)
            {
                sb.Append('"');
            }
        }

        return sb?.ToString();
    }

internal static bool TryParseModelId(string output, out string modelId)
    {
        // Foundry CLI emits model info as a fixed-width table:
        //   Alias                          Device     Task           File Size    License      Model ID
        //   phi-3.5-mini                   GPU        chat           2.16 GB      MIT          Phi-3.5-mini-instruct-generic-gpu:1
        using var reader = new StringReader(output);
        string? line;
        var modelIdStart = -1;
        while ((line = reader.ReadLine()) is not null)
        {
            if (modelIdStart < 0)
            {
                modelIdStart = line.IndexOf("Model ID", StringComparison.Ordinal);
                continue;
            }

            if (line.Length <= modelIdStart || line.All(c => c == '-' || char.IsWhiteSpace(c)))
            {
                continue;
            }

            var candidate = line[modelIdStart..].Trim();
            if (candidate.Length > 0)
            {
                modelId = candidate.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries)[0];
                return true;
            }
        }

        modelId = string.Empty;
        return false;
    }

private static bool IsSimpleType(ITypeSymbol type, WellKnownTypes wellKnownTypes)
    {
        // Primitives via SpecialType
        if (type.SpecialType switch
        {
            SpecialType.System_Boolean => true,
            SpecialType.System_Byte => true,
            SpecialType.System_SByte => true,
            SpecialType.System_Int16 => true,
            SpecialType.System_UInt16 => true,
            SpecialType.System_Int32 => true,
            SpecialType.System_UInt32 => true,
            SpecialType.System_Int64 => true,
            SpecialType.System_UInt64 => true,
            SpecialType.System_Single => true,
            SpecialType.System_Double => true,
            SpecialType.System_Decimal => true,
            SpecialType.System_Char => true,
            SpecialType.System_String => true,
            SpecialType.System_DateTime => true,
            SpecialType.System_Object => true, // Maps to 'any' in ATS
            _ => false
        })
        {
            return true;
        }

        // Well-known scalar types using symbol comparison
        return IsWellKnownScalarType(type, wellKnownTypes);
    }

private void EmitBrowserConfigurationOnce(TextWriter output)
    {
        if (_browserConfigurationEmitted)
        {
            return;
        }

        _browserConfigurationEmitted = true;

        var config = _httpContext.GetBrowserConfiguration();

        // Apply framework defaults: environment name and tooling env vars
        var hostEnvironment = _httpContext.RequestServices.GetRequiredService<IHostEnvironment>();
        config.WebAssembly.EnvironmentName ??= hostEnvironment.EnvironmentName;

        if (s_dotnetModifiableAssemblies != null)
        {
            config.WebAssembly.EnvironmentVariables.TryAdd("DOTNET_MODIFIABLE_ASSEMBLIES", s_dotnetModifiableAssemblies);
        }

        if (s_aspnetcoreBrowserTools != null)
        {
            config.WebAssembly.EnvironmentVariables.TryAdd("__ASPNETCORE_BROWSER_TOOLS", s_aspnetcoreBrowserTools);
        }

        var configJson = JsonSerializer.Serialize(config, BrowserConfigurationJsonContext.Default.BrowserConfiguration);
        var configBase64 = Convert.ToBase64String(Encoding.UTF8.GetBytes(configJson));
        output.Write("<!--Blazor-Configuration:");
        output.Write(configBase64);
        output.Write("-->");
    }

internal static ErrorEventArgs Read(JsonElement jsonElement)
    {
        var eventArgs = new ErrorEventArgs();
        foreach (var property in jsonElement.EnumerateObject())
        {
            if (property.NameEquals(Message.EncodedUtf8Bytes))
            {
                eventArgs.Message = property.Value.GetString()!;
            }
            else if (property.NameEquals(Colno.EncodedUtf8Bytes))
            {
                eventArgs.Colno = property.Value.GetInt32();
            }
            else if (property.NameEquals(Filename.EncodedUtf8Bytes))
            {
                eventArgs.Filename = property.Value.GetString()!;
            }
            else if (property.NameEquals(Lineno.EncodedUtf8Bytes))
            {
                eventArgs.Lineno = property.Value.GetInt32();
            }
            else if (property.NameEquals(Type.EncodedUtf8Bytes))
            {
                eventArgs.Type = property.Value.GetString()!;
            }
            else
            {
                throw new JsonException($"Unknown property {property.Name}");
            }
        }
        return eventArgs;
    }

