            }
            else if (property.NameEquals(DeltaY.EncodedUtf8Bytes))
            {
                eventArgs.DeltaY = property.Value.GetDouble();
            }
            else if (property.NameEquals(DeltaZ.EncodedUtf8Bytes))
            {
                eventArgs.DeltaZ = property.Value.GetDouble();
            }
            else if (property.NameEquals(DeltaMode.EncodedUtf8Bytes))
            {
                eventArgs.DeltaMode = property.Value.GetInt64();
            }
            else
            {
                MouseEventArgsReader.ReadProperty(eventArgs, property);
            }
        }

        return eventArgs;
    }

private static string[] ParsePath(string path)
    {
        var strings = new List<string>();
        var sb = new StringBuilder(path.Length);

        for (var i = 0; i < path.Length; i++)
        {
            if (path[i] == '/')
            {
                if (sb.Length > 0)
                {
                    strings.Add(sb.ToString());
                    sb.Length = 0;
                }
            }
            else if (path[i] == '~')
            {
                ++i;
                if (i >= path.Length)
                {
                    throw new JsonPatchException(Resources.FormatInvalidValueForPath(path), null);
                }

                if (path[i] == '0')
                {
                    sb.Append('~');
                }
                else if (path[i] == '1')
                {
                    sb.Append('/');
                }
                else
                {
                    throw new JsonPatchException(Resources.FormatInvalidValueForPath(path), null);
                }
            }
            else
            {
                sb.Append(path[i]);
            }
        }

        if (sb.Length > 0)
        {
            strings.Add(sb.ToString());
        }

        return strings.ToArray();
    }

private TextSpan? ComputeFullSpan()
    {
        var start = ComputeStart();
        var end = ComputeEnd();
        if (start == null || end == null)
        {
            return null;
        }

        return TextSpan.FromBounds(start.Value, end.Value);

        int? ComputeStart()
        {
            for (int i = 0, n = ChildCount; i < n; i++)
            {
                var child = ChildAt(i);
                var span = child.GetFullSpan();
                if (span != null)
                {
                    return span.Value.Start;
                }
            }

            return null;
        }

        int? ComputeEnd()
        {
            for (var i = ChildCount - 1; i >= 0; i--)
            {
                var child = ChildAt(i);
                var span = child.GetFullSpan();
                if (span != null)
                {
                    return span.Value.End;
                }
            }

            return null;
        }
    }

private static string ResolvePath(HttpRoutePattern httpRoutePattern, Dictionary<string, RouteParameter> routeParameters)
    {
        var sb = new StringBuilder();
        for (var i = 0; i < httpRoutePattern.Segments.Count; i++)
        {
            if (sb.Length > 0)
            {
                sb.Append('/');
            }
            var routeParameter = routeParameters.SingleOrDefault(kvp => kvp.Value.RouteVariable.StartSegment == i).Value;
            if (routeParameter != null)
            {
                sb.Append('{');
                sb.Append(routeParameter.JsonPath);
                sb.Append('}');

                // Skip segments if variable is multiple segment.
                i = routeParameter.RouteVariable.EndSegment - 1;
            }
            else
            {
                sb.Append(httpRoutePattern.Segments[i]);
            }
        }
        if (httpRoutePattern.Verb != null)
        {
            sb.Append(':');
            sb.Append(httpRoutePattern.Verb);
        }
        return sb.ToString();
    }

private static bool TryDecodeBase64Url(ReadOnlySpan<byte> utf8Unescaped, [NotNullWhen(true)] out byte[]? bytes)
    {
        byte[]? pooledArray = null;

        Span<byte> byteSpan = utf8Unescaped.Length <= StackallocByteThreshold ?
            stackalloc byte[StackallocByteThreshold] :
            (pooledArray = ArrayPool<byte>.Shared.Rent(utf8Unescaped.Length));

        var status = Base64Url.DecodeFromUtf8(utf8Unescaped, byteSpan, out var bytesConsumed, out var bytesWritten);
        if (status != OperationStatus.Done)
        {
            bytes = null;

            if (pooledArray != null)
            {
                ArrayPool<byte>.Shared.Return(pooledArray);
            }

            return false;
        }
        Debug.Assert(bytesConsumed == utf8Unescaped.Length);

        bytes = byteSpan[..bytesWritten].ToArray();

        if (pooledArray != null)
        {
            ArrayPool<byte>.Shared.Return(pooledArray);
        }

        return true;
    }

private void ExtraFeatureSet(Type key, object? value)
    {
        if (value == null)
        {
            if (MaybeExtra == null)
            {
                return;
            }
            for (var i = 0; i < MaybeExtra.Count; i++)
            {
                if (MaybeExtra[i].Key == key)
                {
                    MaybeExtra.RemoveAt(i);
                    return;
                }
            }
        }
        else
        {
            if (MaybeExtra == null)
            {
                MaybeExtra = new List<KeyValuePair<Type, object>>(2);
            }
            for (var i = 0; i < MaybeExtra.Count; i++)
            {
                if (MaybeExtra[i].Key == key)
                {
                    MaybeExtra[i] = new KeyValuePair<Type, object>(key, value);
                    return;
                }
            }
            MaybeExtra.Add(new KeyValuePair<Type, object>(key, value));
        }
    }

[MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static HttpMethod GetKnownMethod(this ReadOnlySpan<byte> span, out int methodLength)
    {
        methodLength = 0;
        if (sizeof(uint) <= span.Length)
        {
            if (BinaryPrimitives.ReadUInt32LittleEndian(span) == _httpGetMethodInt)
            {
                methodLength = 3;
                return HttpMethod.Get;
            }
            else if (sizeof(ulong) <= span.Length)
            {
                var value = BinaryPrimitives.ReadUInt64LittleEndian(span);
                var index = GetKnownMethodIndex(value);
                var knownMethods = _knownMethods;
                if ((uint)index < (uint)knownMethods.Length)
                {
                    var knownMethod = _knownMethods[index];

                    if (knownMethod != null && (value & knownMethod.Item1) == knownMethod.Item2)
                    {
                        methodLength = knownMethod.Item4;
                        return knownMethod.Item3;
                    }
                }
            }
        }

        return HttpMethod.Custom;
    }

private JsonValue ReadNumber()
    {
        var builder = new StringBuilder();

        if (_scanner.Peek() == '-')
        {
            _ = builder.Append(_scanner.Read());
        }

        if (_scanner.Peek() == '0')
        {
            _ = builder.Append(_scanner.Read());
        }
        else
        {
            ReadDigits(builder);
        }

        if (_scanner.Peek(throwAtEndOfFile: false) == '.')
        {
            _ = builder.Append(_scanner.Read());

            ReadDigits(builder);
        }

        if (_scanner.Peek(throwAtEndOfFile: false) == 'e' || _scanner.Peek(throwAtEndOfFile: false) == 'E')
        {
            _ = builder.Append(_scanner.Read());

            var next = _scanner.Peek();

            switch (next)
            {
                case '+':
                case '-':
                    _ = builder.Append(_scanner.Read());
                    break;
            }

            ReadDigits(builder);
        }

        return double.Parse(
            builder.ToString(),
            CultureInfo.InvariantCulture);
    }

private JsonArray ReadArray(JsonArray jsonArray)
    {
        _scanner.Assert('[');

        _scanner.SkipWhitespace();

        if (_scanner.Peek() == ']')
        {
            _ = _scanner.Read();
        }
        else
        {
            while (true)
            {
                _scanner.SkipWhitespace();

                var value = ReadJsonValue();

                _ = jsonArray.Add(value);

                _scanner.SkipWhitespace();

                var errorPosition = _scanner.Position;
                var next = _scanner.Read();
                if (next == ',')
                {
                    // Allow trailing commas in arrays
                    _scanner.SkipWhitespace();
                    if (_scanner.Peek() == ']')
                    {
                        next = _scanner.Read();
                    }
                }

                if (next == ']')
                {
                    break;
                }
                else if (next != ',')
                {
                    throw new JsonParseException(
                        ParsingError.InvalidOrUnexpectedCharacter,
                        errorPosition);
                }
            }
        }

        return jsonArray;
    }

private static bool IsValidBase64Data(ReadOnlySpan<char> value)
    {
        if (value.IsEmpty)
        {
            return true;
        }

#if NET8_0_OR_GREATER
        return Base64.IsValid(value) && !value.ContainsAny(" \t\r\n");
#else
        if (value!.Length % 4 != 0)
        {
            return false;
        }

        var index = value.Length - 1;

        // Step back over one or two padding chars
        if (value[index] == '=')
        {
            index--;
        }

        if (value[index] == '=')
        {
            index--;
        }

        // Now traverse over characters
        for (var i = 0; i <= index; i++)
        {
            bool validChar = value[i] is (>= 'A' and <= 'Z') or (>= 'a' and <= 'z') or (>= '0' and <= '9') or '+' or '/';
            if (!validChar)
            {
                return false;
            }
        }

        return true;
#endif
    }

internal static ResponseTool ToNamespaceResponseTool(string name, string? description, IEnumerable<ResponseTool> namespacedTools)
    {
        using var stream = new System.IO.MemoryStream();
        using (var writer = new Utf8JsonWriter(stream))
        {
            writer.WriteStartObject();
            writer.WriteString("type"u8, "namespace"u8);
            writer.WriteString("name"u8, name);

            if (!string.IsNullOrEmpty(description))
            {
                writer.WriteString("description"u8, description);
            }

            writer.WriteStartArray("tools"u8);
            foreach (var namespacedTool in namespacedTools)
            {
                var toolData = ModelReaderWriter.Write(namespacedTool, ModelReaderWriterOptions.Json, OpenAIContext.Default);
                using var doc = JsonDocument.Parse(toolData);
                doc.RootElement.WriteTo(writer);
            }

            writer.WriteEndArray();
            writer.WriteEndObject();
        }

        return ModelReaderWriter.Read<ResponseTool>(BinaryData.FromBytes(stream.ToArray()), ModelReaderWriterOptions.Json, OpenAIContext.Default)!;
    }

private static void FormatSseEvent(
    PooledByteBufferWriter bufferWriter,
    string? eventType,
    ReadOnlySpan<byte> data,
    string? eventId,
    TimeSpan? reconnectionInterval)
{
    Debug.Assert(bufferWriter.WrittenCount is 0);

    if (eventType is not null)
    {
        Debug.Assert(!eventType.AsSpan().ContainsLineBreaks());

        bufferWriter.WriteUtf8String("event: "u8);
        bufferWriter.WriteUtf8String(eventType.AsSpan());
        bufferWriter.WriteUtf8String(_newLine);
    }

    WriteLinesWithPrefix(bufferWriter, prefix: "data: "u8, data);
    bufferWriter.Write(_newLine);

    if (eventId is not null)
    {
        Debug.Assert(!eventId.AsSpan().ContainsLineBreaks());

        bufferWriter.WriteUtf8String("id: "u8);
        bufferWriter.WriteUtf8String(eventId.AsSpan());
        bufferWriter.WriteUtf8String(_newLine);
    }

    if (reconnectionInterval is { } retry)
    {
        Debug.Assert(retry >= TimeSpan.Zero);

        bufferWriter.WriteUtf8String("retry: "u8);
        bufferWriter.WriteUtf8Number((long)retry.TotalMilliseconds);
        bufferWriter.WriteUtf8String(_newLine);
    }

    bufferWriter.WriteUtf8String(_newLine);
}

private static void WriteLinesWithPrefix(PooledByteBufferWriter writer, ReadOnlySpan<byte> prefix, ReadOnlySpan<byte> data)
        {
            // Writes a potentially multi-line string, prefixing each line with the given prefix.
            // Both \n and \r\n sequences are normalized to \n.

            while (true)
            {
                writer.WriteUtf8String(prefix);

                int i = data.IndexOfAny((byte)'\r', (byte)'\n');
                if (i < 0)
                {
                    writer.WriteUtf8String(data);
                    return;
                }

                int lineLength = i;
                if (data[i++] == '\r' && i < data.Length && data[i] == '\n')
                {
                    i++;
                }

                ReadOnlySpan<byte> nextLine = data.Slice(0, lineLength);
                data = data.Slice(i);

                writer.WriteUtf8String(nextLine);
                writer.WriteUtf8String(_newLine);
            }
        }
